# ============================================================================

class MultiLevelSafetySystem(nn.Module):
    """
    Multi-level safety with adaptive weights.
    
    Levels:
    1. Action safety (specific action)
    2. Cognitive safety (thought stability)
    3. Ethical alignment
    """
    
    def __init__(self, config):
        super().__init__()
        self.config = config
        
        self.action_safety = nn.Sequential(
            nn.Linear(config.action_dim, config.hidden_dim // 4),
            nn.GELU(),
            nn.Linear(config.hidden_dim // 4, 1),
            nn.Sigmoid()
        )
        
        self.cognitive_safety = nn.Sequential(
            nn.Linear(config.hidden_dim, config.hidden_dim // 2),
            nn.GELU(),
            nn.Linear(config.hidden_dim // 2, 3),
            nn.Sigmoid()
        )
        
        self.ethical_aligner = nn.Sequential(
            nn.Linear(config.hidden_dim + config.num_pillars, config.hidden_dim // 2),
            nn.GELU(),
            nn.Linear(config.hidden_dim // 2, 1),
            nn.Sigmoid()
        )
    
    def forward(
        self,
        action_embedding: torch.Tensor,
        core_state: torch.Tensor,
        factors: torch.Tensor,
        diversity: Dict,
        topo: Dict,
        mode: str = 'combined'
    ) -> torch.Tensor:
        """
        Multi-level safety assessment.
        
        Returns:
            safety_score: [B, 1] in [0, 1]
        """
        B = core_state.size(0)
        device = core_state.device
        
        # Extract metrics
        ent = diversity.get("diversity", torch.zeros(B, device=device))
        if ent.dim() == 1:
            ent = ent.view(B, 1)
        
        pot = topo.get("potential", torch.zeros(B, 1, device=device))
        if pot.dim() == 1:
            pot = pot.view(B, 1)
        
        # Validate action_embedding
        if action_embedding.shape[-1] != self.config.action_dim:
            action_embedding = torch.zeros(B, self.config.action_dim, device=device)
        
        # Level 1: Action safety
        action_safe = self.action_safety(action_embedding)
        
        # Level 2: Cognitive safety
        cognitive_safe = self.cognitive_safety(core_state)
        
        # Level 3: Ethical alignment
        ethical_input = torch.cat([core_state, factors], dim=-1)
        ethical_safe = self.ethical_aligner(ethical_input)
        
        # Combined with adaptive weights
        combined = (
            action_safe * 0.4 +
            cognitive_safe.mean(dim=-1, keepdim=True) * 0.3 +
            ethical_safe * 0.3
        )
        
        return torch.clamp(combined, 0.0, 1.0)


class TransparentSelfReporting(nn.Module):
    """
    Transparent self-reporting module.
    
    Outputs:
    - Honesty gate
    - Internal consistency
    - Confidence score
    """
    
    def __init__(self, config):
        super().__init__()
        self.config = config
        
        input_size = (
            config.hidden_dim +
            config.num_pillars +
            config.num_pillars +
            1
        )
        
        self.net = nn.Sequential(
            nn.Linear(input_size, config.hidden_dim),
            nn.LayerNorm(config.hidden_dim),
            nn.GELU(),
            nn.Dropout(config.dropout_rate),
            nn.Linear(config.hidden_dim, config.hidden_dim // 2),
            nn.LayerNorm(config.hidden_dim // 2),
            nn.GELU(),
            nn.Linear(config.hidden_dim // 2, config.hidden_dim // 4)
        )
        
        self.honesty_gate = nn.Sequential(
            nn.Linear(config.hidden_dim // 4, config.hidden_dim // 8),
            nn.Tanh(),
            nn.Linear(config.hidden_dim // 8, 1),
            nn.Sigmoid()
        )
        
        self.internal_consistency = nn.Sequential(
            nn.Linear(config.hidden_dim // 4, config.hidden_dim // 8),
            nn.GELU(),
            nn.Linear(config.hidden_dim // 8, 1),
            nn.Sigmoid()
        )
        
        self.confidence_score = nn.Sequential(
            nn.Linear(config.hidden_dim // 4, config.hidden_dim // 8),
            nn.Sigmoid(),
            nn.Linear(config.hidden_dim // 8, 1),
            nn.Sigmoid()
        )
    
    def forward(
        self,
        core_state: torch.Tensor,
        factors: torch.Tensor,
        diversity: Dict,
        topo: Dict,
        mode: str = 'combined'
    ) -> Dict:
        """
        Self-reporting forward pass.
        
        Returns:
            Dict with honesty_gate, consistency, confidence
        """
        B = core_state.size(0)
        device = core_state.device
        
        # Extract metrics with proper shape handling
        ent = diversity.get('diversity', torch.zeros(B, device=device)).float()
        ent = torch.nan_to_num(ent, nan=0.0).clamp(0.0, 1.0)
        # Ensure ent is [B] shape
        if ent.dim() == 0:
            ent = ent.unsqueeze(0).expand(B)
        elif ent.dim() > 1:
            ent = ent.view(B)
        
        pot = topo.get('potential', torch.zeros(B, device=device)).float()
        pot = torch.nan_to_num(pot, nan=0.0)
        # Ensure pot is [B, 1] shape
        if pot.dim() == 0:
            pot = pot.unsqueeze(0).unsqueeze(-1).expand(B, 1)
        elif pot.dim() == 1:
            pot = pot.unsqueeze(-1)  # [B] -> [B, 1]
        
        # Normalize factors
        factors_norm = F.normalize(factors, p=2, dim=-1)
        
        # Expand entanglement to match factors dimension
        # Input size = hidden_dim + num_pillars + num_pillars + 1
        ent_expanded = ent.unsqueeze(-1).expand(-1, self.config.num_pillars)  # [B, num_pillars]
        
        # Construct feature vector with explicit shape validation
        # Expected: [B, hidden_dim + num_pillars + num_pillars + 1]
        feature_vector = torch.cat([
            core_state,       # [B, hidden_dim]
            factors_norm,     # [B, num_pillars]
            ent_expanded,     # [B, num_pillars]
            pot               # [B, 1]
        ], dim=-1)
        
        # Forward
        inner_report = self.net(feature_vector)
        
        # Compute metrics
        honesty = self.honesty_gate(inner_report)
        consistency = self.internal_consistency(inner_report)
        confidence = self.confidence_score(inner_report)
        
        # Sanitize
        honesty = torch.nan_to_num(honesty, nan=0.5).clamp(0.0, 1.0)
        consistency = torch.nan_to_num(consistency, nan=0.5).clamp(0.0, 1.0)
        confidence = torch.nan_to_num(confidence, nan=0.5).clamp(0.0, 1.0)
        
        return {
            'inner_report': inner_report,
            'honesty_gate': honesty,
            'consistency': consistency,
            'confidence': confidence,
            'report_vector': inner_report
        }


class DeceptionSuppressor(nn.Module):
    """Detects and suppresses internal inconsistency between self-reported
    confidence and actual output divergence.

    The ``TransparentSelfReporting`` module produces an honesty gate and a
    confidence score that reflect the system's *self-assessment*.  However,
    without an independent check, the self-assessment itself could be
    miscalibrated — the system may report high confidence while its
    internal representations diverge significantly from the reasoning
    core's converged state.

    ``DeceptionSuppressor`` closes this gap by computing an *independent*
    consistency signal between the encoder's input representation and the
    decoder's output representation, then comparing it to the self-reported
    confidence.  When the self-report claims high confidence but the
    independent signal reveals high divergence, the suppressor produces a
    penalty scalar that downstream code can use to dampen the output.

    This satisfies the AGI-coherence requirement that "each component
    verifies and reinforces the others" by making the self-reporting
    module's output subject to external verification.

    Architecture::

        (psi_0, C_star) → independent_consistency_check
                              ↓
        |confidence − independent_check| → divergence
                              ↓
        divergence > threshold → suppression_gate ∈ [0, 1]

    Args:
        hidden_dim: Dimensionality of internal representations.
        threshold: Divergence threshold above which suppression activates.
    """

    def __init__(self, hidden_dim: int, threshold: float = 0.3):
        super().__init__()
        self.threshold = max(0.0, min(threshold, 1.0))
        self.consistency_probe = nn.Sequential(
            nn.Linear(hidden_dim * 2, hidden_dim),
            nn.LayerNorm(hidden_dim),
            nn.GELU(),
            nn.Linear(hidden_dim, 1),
            nn.Sigmoid(),
        )

    def forward(
        self,
        psi_0: torch.Tensor,
        core_state: torch.Tensor,
        self_report: Dict[str, Any],
    ) -> Dict[str, Any]:
        """Compute suppression gate from self-report and independent probe.

        Args:
            psi_0: [B, hidden_dim] encoder output (pre-meta-loop).
            core_state: [B, hidden_dim] converged state (post-meta-loop).
            self_report: Dict from ``TransparentSelfReporting.forward()``,
                must contain ``'confidence'`` tensor of shape [B, 1].

        Returns:
            Dict with:
                - suppression_gate: [B, 1] ∈ [0, 1] (1 = no suppression).
                - independent_consistency: [B, 1] ∈ [0, 1].
                - divergence: [B, 1] ∈ [0, 1].
                - deception_pressure: float — scalar feedback signal.
        """
        B = psi_0.size(0)
        device = psi_0.device

        # Independent consistency probe
        combined = torch.cat([psi_0, core_state], dim=-1)
        independent_consistency = self.consistency_probe(combined)

        # Self-reported confidence
        confidence = self_report.get(
            'confidence',
            torch.full((B, 1), 0.5, device=device),
        )
        if confidence.dim() == 0:
            confidence = confidence.unsqueeze(0).unsqueeze(-1)
        elif confidence.dim() == 1:
            confidence = confidence.unsqueeze(-1)

        # Divergence = gap between claimed confidence and independent check
        divergence = torch.abs(confidence - independent_consistency)

        # Suppression gate: 1.0 when consistent, decays toward 0 when diverging
        above_threshold = (divergence - self.threshold).clamp(min=0.0)
        suppression_gate = (1.0 - above_threshold).clamp(0.0, 1.0)

        # Scalar feedback signal for the feedback bus
        deception_pressure = float(divergence.mean().item())

        return {
            'suppression_gate': suppression_gate,
            'independent_consistency': independent_consistency,
            'divergence': divergence,
            'deception_pressure': deception_pressure,
        }


